#include <iostream>
using namespace std;

class Box {
public:
    int length, width;

    Box() : length(0), width(0) {  // Default
        cout << "Default constructor called\n";
    }

    Box(int l, int w) : length(l), width(w) {  // Parameterized
        cout << "Parameterized constructor called\n";
    }

    Box(const Box& b) : length(b.length), width(b.width) {  // Copy
        cout << "Copy constructor called\n";
    }

    ~Box() { cout << "Destructor called\n"; }

    int area() { return length * width; }
};

int main() {
    Box b1(5, 3);
    Box b2 = b1;  // Copy constructor
    cout << "Area: " << b1.area() << endl;
    return 0;
}

#include <iostream>
using namespace std;

class BankAccount {
private:
    double balance;
    string owner;
public:
    BankAccount(string o, double b) : owner(o), balance(b) {}

    void deposit(double amount) {
        if (amount > 0) balance += amount;
        else cout << "Invalid deposit amount\n";
    }

    bool withdraw(double amount) {
        if (amount > 0 && amount <= balance) {
            balance -= amount;
            return true;
        }
        cout << "Insufficient funds\n";
        return false;
    }

    double getBalance() const { return balance; }
    string getOwner() const { return owner; }
};

int main() {
    BankAccount acc("Alice", 1000.0);
    acc.deposit(500);
    acc.withdraw(200);
    cout << "Balance: $" << acc.getBalance() << endl;
    return 0;
}

#include <iostream>
using namespace std;

class Shape {  // Abstract class
public:
    virtual double area() = 0;    // Pure virtual
    virtual double perimeter() = 0; // Pure virtual
    virtual void display() {
        cout << "Area: " << area() << ", Perimeter: " << perimeter() << endl;
    }
    virtual ~Shape() {}
};

class Circle : public Shape {
    double radius;
public:
    Circle(double r) : radius(r) {}
    double area() override { return 3.14159 * radius * radius; }
    double perimeter() override { return 2 * 3.14159 * radius; }
};

class Rectangle : public Shape {
    double w, h;
public:
    Rectangle(double w, double h) : w(w), h(h) {}
    double area() override { return w * h; }
    double perimeter() override { return 2 * (w + h); }
};

int main() {
    Shape* shapes[] = { new Circle(5), new Rectangle(4, 6) };
    for (auto s : shapes) s->display();
    return 0;
}

