// Function template
template<typename T>
T getMax(T a, T b) {
    return (a > b) ? a : b;
}

// Class template
template<typename T>
class Stack {
    vector<T> data;
public:
    void push(T item) { data.push_back(item); }
    T pop() {
        T top = data.back();
        data.pop_back();
        return top;
    }
    bool empty() { return data.empty(); }
};

int main() {
    cout << getMax(3, 7) << endl;       // int: 7
    cout << getMax(3.14, 2.71) << endl; // double: 3.14

    Stack<int> s;
    s.push(1); s.push(2); s.push(3);
    cout << s.pop() << endl;  // 3
    return 0;
}

#include <iostream>
#include <memory>
using namespace std;

class Resource {
public:
    Resource(string n) : name(n) { cout << name << " created\n"; }
    ~Resource() { cout << name << " destroyed\n"; }
    string name;
};

int main() {
    // Raw pointer (manual management)
    Resource* raw = new Resource("Raw");
    delete raw;  // Must manually delete

    // unique_ptr (auto cleanup)
    auto uptr = make_unique<Resource>("Unique");
    // No need to delete!

    // shared_ptr
    auto sptr1 = make_shared<Resource>("Shared");
    auto sptr2 = sptr1;  // Ref count = 2
    cout << "Ref count: " << sptr1.use_count() << endl;
    return 0;
}
